+            "CREATE TABLE dest(id INTEGER PRIMARY KEY, total INTEGER DEFAULT 0, label TEXT)",
+        ];
+        for s in &setup {
+            fconn.execute(s).unwrap();
+            rconn.execute_batch(s).unwrap();
+        }
+
+        // INSERT...SELECT with GROUP BY
+        let ins =
